+	if tracker.baselineRuneCount == 0 {
+		t.Fatal("expected baseline rune count after initial update")
+	}
+
+	tracker.Reset()
+
+	if tracker.baselineHash != "" {
+		t.Fatalf("baseline hash should be cleared after reset, got %q", tracker.baselineHash)
+	}
