+		"mail":              {"coordination_section", "agent_mail_status"},
+		"alerts":            {"alerts_section", "incident_detection"},
+	}
+
+	affectedFeatures := make(map[string][]string) // feature -> affected sources
+
+	for _, sourceName := range health.Degraded {
