+		// Fallback to in-memory journal
+		return f.journal.Replay(sinceCursor, limit)
+	}
+
+	// Handle cursor=-1 (start from now)
+	if sinceCursor == -1 {
+		return []AttentionEvent{}, maxCursor(window.NewestCursor, f.cursor.Current()), nil
