+func TestAttentionFeed_StoreBackedPersistence(t *testing.T) {
+	t.Parallel()
+
+	store := newTestAttentionStore(t)
+
+	feed := NewAttentionFeed(AttentionFeedConfig{
+		JournalSize:       100,
+		RetentionPeriod:   time.Hour,
