+		t.Fatalf("appended event should have positive cursor, got %d", appended.Cursor)
+	}
+
+	// Verify replay from store works
+	replayed, latestCursor, err := feed.Replay(0, 10)
+	if err != nil {
+		t.Fatalf("Replay error: %v", err)
