+	if len(replayed) != 1 {
+		t.Fatalf("expected 1 replayed event, got %d", len(replayed))
+	}
+	if replayed[0].Cursor != appended.Cursor {
+		t.Fatalf("replayed cursor = %d, want %d", replayed[0].Cursor, appended.Cursor)
